SELECT a.*, ste.site_nm AS site_nm, cd_at.code_label AS alarm_type_cd_nm, cd_ac.code_label AS channel_cd_nm, cd_att.code_label AS target_type_cd_nm FROM sy_alarm a LEFT JOIN sy_site ste ON ste.site_id = a.site_id LEFT JOIN sy_code cd_at ON cd_at.code_grp = 'ALARM_TYPE' AND cd_at.code_value = a.alarm_type_cd LEFT JOIN sy_code cd_ac ON cd_ac.code_grp = 'ALARM_CHANNEL' AND cd_ac.code_value = a.channel_cd LEFT JOIN sy_code cd_att ON cd_att.code_grp = 'ALARM_TARGET_TYPE' AND cd_att.code_value = a.target_type_cd
ORDER BY a.alarm_id ASC ORDER BY a.alarm_id DESC ORDER BY a.alarm_title ASC ORDER BY a.alarm_title DESC ORDER BY a.alarm_send_date ASC ORDER BY a.alarm_send_date DESC ORDER BY a.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

